def test_get_user_display_name_handles_valid_profile():
    user_data = {'profile': {'display_name': 'John Doe'}}
    assert get_user_display_name(user_data) == 'John Doe', "Should return the display name from valid profile data"

def test_get_user_display_name_handles_none_profile():
    user_data = {'profile': None}
    try:
        result = get_user_display_name(user_data)
    except TypeError:
        assert False, "Function should raise TypeError when 'profile' is None."

    assert result == "TypeError: 'NoneType' object is not subscriptable"
